      invariant forall pos | 0 <= pos < n && j <= pos < r ::
        ans[pos] == EffectiveCap(pos, h, restrictions[..i])
    {
      ghost var old_val := ans[j];
      EffectiveCapStep(j, h, restrictions, i);

      if ans[j] > x {
