      }
      j := j + 1;
    }

    // Unify: for positions outside [l-1, r), EffectiveCap is unchanged
    forall pos | 0 <= pos < n
      ensures ans[pos] == EffectiveCap(pos, h, restrictions[..i+1])
    {
      if !(l - 1 <= pos < r) {
        EffectiveCapStep(pos, h, restrictions, i);
      }
    }

